3116	fn rbtdrc_lode_lifecycle(dir: &Path) -> rbtdre_Verdict {
3117	    rbtdrc_with_ctx(|ctx| {
3118	        let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
3119	        if !ctx.project_root().join(vessel_dir).is_dir() {
