559	fn rbtdro_git_commit(files: &[String], message: &str) -> Result<(), rbtdre_Verdict> {
560	    let mut status_args: Vec<&str> = vec!["status", "--porcelain", "--"];
561	    status_args.extend(files.iter().map(String::as_str));
