563	        .args(&status_args)
564	        .output()
565	        .map_err(|e| {
566	            rbtdre_Verdict::Fail(format!("git status --porcelain exec failed: {}", e))
567	        })?;
568	    if !status.status.success() {
569	        return Err(rbtdre_Verdict::Fail(format!(
570	            "git status --porcelain exited {}",
571	            status.status.code().unwrap_or(-1)
572	        )));
573	    }
574	    if String::from_utf8_lossy(&status.stdout).trim().is_empty() {
575	        // None of the owned files changed — clean no-op, not an error.
576	        return Ok(());
577	    }
578	
